def sifre_dogrula(sifre):
    if len(sifre) < 8:
        return False

    has_buyuk_harf = False
    has_rakam = False

    for karakter in sifre:
        if karakter.isupper():
            has_buyuk_harf = True
        if karakter.isdigit():
            has_rakam = True

    return has_buyuk_harf and has_rakam
